+import AppKit
+
+enum SoundEffect: Equatable {
+    case startRecording
+    case stopRecording
+}
+
+protocol SoundEffectPlaying: AnyObject {
+    func play(_ effect: SoundEffect)
+}
+
+final class SystemSoundPlayer: SoundEffectPlaying {
+    private let startSound = NSSound(named: NSSound.Name("Tink"))
+    private let stopSound = NSSound(named: NSSound.Name("Pop"))
+
+    func play(_ effect: SoundEffect) {
+        let sound = switch effect {
+        case .startRecording:
+            startSound
+        case .stopRecording:
+            stopSound
+        }
+
+        sound?.stop()
+        sound?.play()
+    }
+}

